package org.apache.commons.csv;
import java.io.Serializable;
import java.util.Arrays;
import java.util.Iterator;
import java.util.List;
import java.util.Map.Entry;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.util.HashMap;
import java.util.Map;

import org.junit.jupiter.api.Test;

class CSVRecordTest {

    @Test
    void testGet_withEnum_existingMapping() {
        // Arrange
        String[] values = {"value0", "value1", "value2"};
        Map<String, Integer> mapping = new HashMap<>();
        mapping.put("ENUM_NAME", 1);
        CSVRecord record = new CSVRecord(values, mapping, null, 1L);

        // Create enum mock with class and name method
        Enum<?> enumMock = mock(Enum.class);
        when(enumMock.toString()).thenReturn("ENUM_NAME");
        when(enumMock.name()).thenReturn("ENUM_NAME");

        // Act
        String result = record.get(enumMock);

        // Assert
        assertEquals("value1", result);
    }

    @Test
    void testGet_withEnum_nonExistingMapping() {
        // Arrange
        String[] values = {"value0", "value1"};
        Map<String, Integer> mapping = new HashMap<>();
        CSVRecord record = new CSVRecord(values, mapping, null, 1L);

        Enum<?> enumMock = mock(Enum.class);
        when(enumMock.toString()).thenReturn("NON_EXISTENT");
        when(enumMock.name()).thenReturn("NON_EXISTENT");

        // Act & Assert
        assertThrows(IllegalArgumentException.class, () -> record.get(enumMock));
    }

    @Test
    void testGet_withEnum_nullEnum() {
        // Arrange
        String[] values = {"value0", "value1"};
        Map<String, Integer> mapping = new HashMap<>();
        CSVRecord record = new CSVRecord(values, mapping, null, 1L);

        // Act & Assert
        assertThrows(NullPointerException.class, () -> record.get((Enum<?>) null));
    }
}
